/**
 * DB-free fake read-only tools over the {@link WORLD}. Covers every v1 tool name
 * the graph may route to for the suite's scenarios, parameterised by the resolved
 * counterparty so per-person amounts stay distinct. The only live dependency of
 * the suite is the LLM; these tools never touch Mongo.
 */
import { createToolResult } from "../../toolResults.js";
import type {
  AssistantToolExecutors,
  AssistantToolName,
  RuntimeToolResult,
  ToolContext,
  ToolResultMetadata
} from "../../state.js";
import {
  WORLD,
  WORLD_RECENT_TX,
  cpOf,
  findCounterpartyByEmail,
  findCounterpartyByQuery,
  fullName,
  maskWorldEmail,
  ordinalFromMessage,
  totalsMemoryUpdate,
  type WorldCounterparty
} from "./world.js";

type Extra = Partial<Pick<Parameters<typeof createToolResult>[0], "data" | "userSummary" | "memoryUpdates" | "status">>;

function r(
  toolName: AssistantToolName,
  summary: string,
  metadata: ToolResultMetadata,
  extra: Extra = {}
): RuntimeToolResult {
  return createToolResult({
    toolName,
    status: extra.status ?? "ok",
    data: extra.data ?? null,
    summary,
    userSummary: extra.userSummary,
    metadata,
    memoryUpdates: extra.memoryUpdates
  });
}

const recipientCp = (ctx: ToolContext): WorldCounterparty | undefined =>
  findCounterpartyByEmail(ctx.resolvedCounterparty?.email);

function txRows() {
  return WORLD_RECENT_TX.map((tx) => {
    const cp = cpOf(tx.cp);
    return {
      transactionId: tx.id,
      label: `${tx.direction} ${tx.amount.toFixed(2)} ILS ${tx.direction === "sent" ? "to" : "from"} ${fullName(cp)}`,
      amount: tx.amount,
      currency: "ILS",
      direction: tx.direction,
      occurredAt: tx.occurredAt,
      counterpartyLabel: maskWorldEmail(cp.email)
    };
  });
}

export function createV2WorldTools(): AssistantToolExecutors {
  return {
    async getUserAccounts() {
      return r("getUserAccounts", `Account: ${WORLD.account.label}.`, {
        recordCount: 1,
        accountLabel: WORLD.account.label
      });
    },
    async getAccountBalance() {
      return r(
        "getAccountBalance",
        `Your ${WORLD.account.label} balance is ${WORLD.account.balance.toFixed(2)} ILS.`,
        { recordCount: 1, accountLabel: WORLD.account.label, amount: WORLD.account.balance }
      );
    },
    async getRecentTransactions() {
      const rows = txRows();
      return r(
        "getRecentTransactions",
        `Recent transactions: ${rows.map((x) => x.label).join("; ")}.`,
        { recordCount: rows.length, transactions: rows },
        {
          data: rows,
          memoryUpdates: {
            transactions: WORLD_RECENT_TX.map((tx) => ({
              transactionId: tx.id,
              label: `${tx.direction} ${tx.amount} ${cpOf(tx.cp).firstName}`,
              counterpartyId: cpOf(tx.cp).email,
              counterpartyLabel: maskWorldEmail(cpOf(tx.cp).email),
              amount: tx.amount,
              currency: "ILS",
              direction: tx.direction,
              occurredAt: tx.occurredAt
            }))
          }
        }
      );
    },
    async searchTransactions() {
      const rows = txRows();
      return r(
        "searchTransactions",
        `Matching transactions: ${rows.map((x) => x.label).join("; ")}.`,
        { recordCount: rows.length, transactions: rows },
        { data: rows }
      );
    },
    async getTransactionStats() {
      const sent = WORLD_RECENT_TX.filter((t) => t.direction === "sent").reduce((s, t) => s + t.amount, 0);
      const received = WORLD_RECENT_TX.filter((t) => t.direction === "received").reduce((s, t) => s + t.amount, 0);
      return r(
        "getTransactionStats",
        `Across ${WORLD_RECENT_TX.length} transactions you sent ${sent.toFixed(2)} ILS and received ${received.toFixed(2)} ILS.`,
        { recordCount: WORLD_RECENT_TX.length, sentAmount: sent, receivedAmount: received }
      );
    },
    async getCashflowSummary() {
      const sent = WORLD_RECENT_TX.filter((t) => t.direction === "sent").reduce((s, t) => s + t.amount, 0);
      const received = WORLD_RECENT_TX.filter((t) => t.direction === "received").reduce((s, t) => s + t.amount, 0);
      return r(
        "getCashflowSummary",
        `Cashflow: ${received.toFixed(2)} ILS in, ${sent.toFixed(2)} ILS out, net ${(received - sent).toFixed(2)} ILS.`,
        { recordCount: 2, receivedAmount: received, sentAmount: sent, netAmount: received - sent }
      );
    },
    async resolveTransactionReference(ctx: ToolContext) {
      const tx = WORLD_RECENT_TX[(ordinalFromMessage(ctx.message) ?? 1) - 1] ?? WORLD_RECENT_TX[0];
      const cp = cpOf(tx.cp);
      return r(
        "resolveTransactionReference",
        `Resolved to ${tx.direction} ${tx.amount.toFixed(2)} ILS with ${fullName(cp)}.`,
        { recordCount: 1, transactionId: tx.id, transactionResolutionStatus: "resolved", amount: tx.amount },
        { data: { transactionId: tx.id } }
      );
    },
    async getTransactionReceipt(ctx: ToolContext) {
      const tx = WORLD_RECENT_TX.find((t) => t.id === ctx.resolvedTransactionId) ?? WORLD_RECENT_TX[0];
      const cp = cpOf(tx.cp);
      return r(
        "getTransactionReceipt",
        `Receipt: ${tx.direction} ${tx.amount.toFixed(2)} ILS ${tx.direction === "sent" ? "to" : "from"} ${fullName(cp)} on ${tx.occurredAt.slice(0, 10)}.`,
        { recordCount: 1, transactionId: tx.id, amount: tx.amount },
        { data: tx }
      );
    },
    async resolveCounterpartyCandidates(ctx: ToolContext) {
      const cp = findCounterpartyByQuery(ctx.message);
      if (!cp) {
        return r("resolveCounterpartyCandidates", "No matching counterparty.", {
          recordCount: 0,
          resolutionStatus: "unresolved"
        }, { status: "empty" });
      }
      return r(
        "resolveCounterpartyCandidates",
        `Resolved to ${fullName(cp)} (${maskWorldEmail(cp.email)}).`,
        {
          recordCount: 1,
          resolutionStatus: "resolved",
          counterpartyEmail: cp.email,
          maskedLabel: maskWorldEmail(cp.email),
          displayName: fullName(cp)
        },
        { data: { email: cp.email }, memoryUpdates: totalsMemoryUpdate(cp, "sent", cp.totalSent) }
      );
    },
    async getLastSentCounterparty() {
      const cp = WORLD.counterparties.maya;
      return r(
        "getLastSentCounterparty",
        `The last person you sent money to was ${fullName(cp)} (${maskWorldEmail(cp.email)}).`,
        { recordCount: 1, counterpartyEmail: cp.email, maskedLabel: maskWorldEmail(cp.email) },
        { data: { email: cp.email, maskedLabel: maskWorldEmail(cp.email), userLabel: cp.email } }
      );
    },
    async getRecentSentCounterparties() {
      const list = [WORLD.counterparties.maya, WORLD.counterparties.dan, WORLD.counterparties.noa];
      return r("getRecentSentCounterparties", `Recent recipients: ${list.map(fullName).join(", ")}.`, {
        recordCount: list.length
      }, { data: list });
    },
    async getRecentReceivedCounterparties() {
      const list = [WORLD.counterparties.dan, WORLD.counterparties.maya];
      return r("getRecentReceivedCounterparties", `Recently received from: ${list.map(fullName).join(", ")}.`, {
        recordCount: list.length
      }, { data: list });
    },
    async getCounterpartySummary(ctx: ToolContext) {
      const cp = recipientCp(ctx) ?? WORLD.counterparties.maya;
      const net = cp.totalReceived - cp.totalSent;
      return r(
        "getCounterpartySummary",
        `With ${fullName(cp)}: sent ${cp.totalSent.toFixed(2)} ILS, received ${cp.totalReceived.toFixed(2)} ILS, net ${net.toFixed(2)} ILS, across ${cp.txCount} transactions.`,
        {
          recordCount: cp.txCount,
          counterpartyEmail: cp.email,
          maskedLabel: maskWorldEmail(cp.email),
          netAmount: net,
          sentAmount: cp.totalSent,
          receivedAmount: cp.totalReceived
        },
        { data: cp, memoryUpdates: totalsMemoryUpdate(cp, "sent", cp.totalSent) }
      );
    },
    async getCounterpartyActivityTimeline(ctx: ToolContext) {
      const cp = recipientCp(ctx) ?? WORLD.counterparties.maya;
      return r(
        "getCounterpartyActivityTimeline",
        `Activity with ${fullName(cp)}: ${cp.txCount} transactions, most recently you sent ${cp.lastSentAmount.toFixed(2)} ILS.`,
        { recordCount: cp.txCount, counterpartyEmail: cp.email }
      );
    },
    async getTransactionsWithCounterparty(ctx: ToolContext) {
      const cp = recipientCp(ctx) ?? WORLD.counterparties.maya;
      return r(
        "getTransactionsWithCounterparty",
        `Transactions with ${fullName(cp)}: most recently you sent ${cp.lastSentAmount.toFixed(2)} ILS; ${cp.txCount} total.`,
        { recordCount: cp.txCount, counterpartyEmail: cp.email, amount: cp.lastSentAmount },
        { memoryUpdates: totalsMemoryUpdate(cp, "sent", cp.totalSent) }
      );
    },
    async getTotalSentToCounterparty(ctx: ToolContext) {
      const cp = recipientCp(ctx);
      if (!cp) return r("getTotalSentToCounterparty", "I need a specific recipient first.", { recordCount: 0 }, { status: "empty" });
      return r(
        "getTotalSentToCounterparty",
        `You have sent ${cp.totalSent.toFixed(2)} ILS in total to ${fullName(cp)}.`,
        { recordCount: cp.txCount, amount: cp.totalSent, counterpartyEmail: cp.email },
        { data: { total: cp.totalSent }, memoryUpdates: totalsMemoryUpdate(cp, "sent", cp.totalSent) }
      );
    },
    async getTotalReceivedFromCounterparty(ctx: ToolContext) {
      const cp = recipientCp(ctx);
      if (!cp) return r("getTotalReceivedFromCounterparty", "I need a specific counterparty first.", { recordCount: 0 }, { status: "empty" });
      return r(
        "getTotalReceivedFromCounterparty",
        `${fullName(cp)} has sent you ${cp.totalReceived.toFixed(2)} ILS in total.`,
        { recordCount: cp.txCount, amount: cp.totalReceived, counterpartyEmail: cp.email },
        { data: { total: cp.totalReceived }, memoryUpdates: totalsMemoryUpdate(cp, "received", cp.totalReceived) }
      );
    },
    async getNetWithCounterparty(ctx: ToolContext) {
      const cp = recipientCp(ctx);
      if (!cp) return r("getNetWithCounterparty", "I need a specific counterparty first.", { recordCount: 0 }, { status: "empty" });
      const net = cp.totalReceived - cp.totalSent;
      return r(
        "getNetWithCounterparty",
        `Your net with ${fullName(cp)} is ${net.toFixed(2)} ILS (received ${cp.totalReceived.toFixed(2)} minus sent ${cp.totalSent.toFixed(2)}).`,
        { recordCount: cp.txCount, amount: net, netAmount: net, counterpartyEmail: cp.email },
        { data: { net }, memoryUpdates: totalsMemoryUpdate(cp, "net", net) }
      );
    },
    async getVerifiedRecipients() {
      const list = Object.values(WORLD.counterparties);
      return r(
        "getVerifiedRecipients",
        `Verified recipients: ${list.map((c) => `${fullName(c)} (${maskWorldEmail(c.email)})`).join(", ")}.`,
        { recordCount: list.length },
        { data: list }
      );
    },
    async getTransferLimits() {
      return r(
        "getTransferLimits",
        `Transfer limits: ${WORLD.limits.perTransfer.toFixed(2)} ILS per transfer, ${WORLD.limits.dailyLimit.toFixed(2)} ILS per day.`,
        { recordCount: 1, amount: WORLD.limits.perTransfer }
      );
    },
    async getTransferEligibility() {
      return r(
        "getTransferEligibility",
        `You can send that amount now; up to ${WORLD.limits.perTransfer.toFixed(2)} ILS per transfer.`,
        { recordCount: 1, amount: WORLD.limits.perTransfer }
      );
    },
    async getTransferQuote() {
      return r("getTransferQuote", "Transfer quote: no fee, prepared in ILS.", { recordCount: 1 });
    },
    async getDailyTransferUsage() {
      return r(
        "getDailyTransferUsage",
        `Today you used ${WORLD.limits.dailyUsed.toFixed(2)} ILS of ${WORLD.limits.dailyLimit.toFixed(2)} ILS; ${WORLD.limits.dailyRemaining.toFixed(2)} ILS remaining.`,
        { recordCount: 2, amount: WORLD.limits.dailyRemaining }
      );
    },
    async getPendingAiTransfers() {
      return r("getPendingAiTransfers", "You have no pending transfer confirmations right now.", {
        recordCount: 0,
        pendingTransfers: []
      }, { status: "empty", data: [] });
    }
  };
}
